#!/usr/bin/env node
/**
 * Single source → multi-agent outputs (2026 layout).
 *
 * Edit only:
 *   - AGENTS.md
 *   - agents/path-rules/*.md
 *   - .agents/skills/<name>/SKILL.md
 *   - agents/prompts/*.md (optional; delegate-expert synced into skill)
 */
import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const BANNER =
  '<!-- GENERATED by `pnpm run sync:agents` — edit AGENTS.md or agents/, not this file. -->\n\n';

const PATH_RULES_DIR = path.join(ROOT, 'agents', 'path-rules');
const SKILLS_SOURCE = path.join(ROOT, '.agents', 'skills');
const AGENTS_MD = path.join(ROOT, 'AGENTS.md');

const SKILL_MIRROR_DIRS = [
  'skills',
  path.join('.github', 'skills'),
  path.join('.claude', 'skills'),
  path.join('.cursor', 'skills'),
];

const GENERATED_README = `# Generated agent skills

Do not edit. Source: [\`.agents/skills/\`](../.agents/skills/).

\`\`\`bash
pnpm run sync:agents
pnpm run agent:install   # gh skill → local Copilot / Claude / Cursor
\`\`\`

See [docs/agent-config.md](../docs/agent-config.md).
`;

function parseFrontmatter(text) {
  const match = text.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n([\s\S]*)$/);
  if (!match) return { meta: {}, body: text };
  const meta = {};
  for (const line of match[1].split('\n')) {
    const m = line.match(/^([\w-]+):\s*(.*)$/);
    if (m) meta[m[1]] = m[2].replace(/^['"]|['"]$/g, '');
  }
  return { meta, body: match[2] };
}

function applyToToGlobs(applyTo) {
  if (!applyTo) return '**/*';
  return applyTo
    .split(',')
    .map((s) => s.trim())
    .join(',');
}

async function exists(p) {
  try {
    await fs.access(p);
    return true;
  } catch {
    return false;
  }
}

async function writeFileEnsuringDir(filePath, content) {
  await fs.mkdir(path.dirname(filePath), { recursive: true });
  await fs.writeFile(filePath, content, 'utf8');
}

async function copySkillsTree(src, dest) {
  await fs.rm(dest, { recursive: true, force: true });
  await fs.mkdir(dest, { recursive: true });
  await fs.cp(src, dest, {
    recursive: true,
    filter: (srcPath) => {
      const base = path.basename(srcPath);
      return base !== 'README.md';
    },
  });
  await fs.writeFile(path.join(dest, 'README.md'), GENERATED_README, 'utf8');
}

async function syncAgentsMd() {
  if (!(await exists(AGENTS_MD))) {
    throw new Error('Missing AGENTS.md at repository root');
  }
  const body = await fs.readFile(AGENTS_MD, 'utf8');
  const out = BANNER + body;
  await writeFileEnsuringDir(path.join(ROOT, '.github', 'copilot-instructions.md'), out);
  console.log('Synced .github/copilot-instructions.md');
}

async function syncPathRules() {
  if (!(await exists(PATH_RULES_DIR))) {
    console.warn('No agents/path-rules/ — skip path rules');
    return;
  }
  const files = (await fs.readdir(PATH_RULES_DIR)).filter((f) => f.endsWith('.md'));
  for (const file of files) {
    const id = file.replace(/\.md$/, '');
    const raw = await fs.readFile(path.join(PATH_RULES_DIR, file), 'utf8');
    const { meta, body } = parseFrontmatter(raw);

    const copilotName = meta.name ? meta.name : id;
    const description = meta.description || `${copilotName} path rules`;
    const applyTo = meta.applyTo || '**/*';
    const globs = applyToToGlobs(applyTo);

    const copilotFront = `---
name: '${copilotName.replace(/'/g, "''")}'
description: '${description.replace(/'/g, "''")}'
applyTo: '${applyTo.replace(/'/g, "''")}'
---

`;
    const copilotPath = path.join(ROOT, '.github', 'instructions', `${id}.instructions.md`);
    await writeFileEnsuringDir(copilotPath, BANNER + copilotFront + body);

    const cursorFront = `---
description: ${description}
globs: ${globs}
alwaysApply: false
---

`;
    const cursorPath = path.join(ROOT, '.cursor', 'rules', `${id}.mdc`);
    await writeFileEnsuringDir(cursorPath, BANNER + cursorFront + body);

    console.log(`Synced path rule: ${id}`);
  }
}

async function syncDelegateExpertSkill() {
  const promptPath = path.join(ROOT, 'agents', 'prompts', 'delegate-expert.md');
  if (!(await exists(promptPath))) return;

  let body = await fs.readFile(promptPath, 'utf8');
  body = body.replace(/^---[\s\S]*?---\r?\n/, '');
  body = body.replace(/copilot-instructions\.md/g, 'AGENTS.md');
  body = body.replace(/list_code_usages/g, 'Grep across the repo for all references');

  const skillDir = path.join(SKILLS_SOURCE, 'delegate-expert');
  await fs.mkdir(skillDir, { recursive: true });
  const skill = `---
name: delegate-expert
description: Generate delegation prompts for specialist agents. Use when delegating tasks, writing expert prompts, or finding a specialist workflow.
disable-model-invocation: true
---

${body.trim()}
`;
  await fs.writeFile(path.join(skillDir, 'SKILL.md'), skill, 'utf8');
  console.log('Synced skill: delegate-expert');
}

async function syncSkillMirrors() {
  if (!(await exists(SKILLS_SOURCE))) {
    throw new Error('Missing .agents/skills/ — add skills there');
  }
  await syncDelegateExpertSkill();
  for (const rel of SKILL_MIRROR_DIRS) {
    const dest = path.join(ROOT, rel);
    await fs.mkdir(path.dirname(dest), { recursive: true });
    await copySkillsTree(SKILLS_SOURCE, dest);
    console.log(`Synced ${rel}`);
  }
}

async function syncCopilotPrompts() {
  const promptPath = path.join(ROOT, 'agents', 'prompts', 'delegate-expert.md');
  if (!(await exists(promptPath))) return;
  const raw = await fs.readFile(promptPath, 'utf8');
  const { meta, body } = parseFrontmatter(raw);
  const name = meta.name || 'Delegate Expert Prompt';
  const description = meta.description || 'Generate delegation prompts for specialists.';
  const out = `---
description: '${description.replace(/'/g, "''")}'
name: '${name.replace(/'/g, "''")}'
argument-hint: '${(meta['argument-hint'] || 'Describe what specialist should do...').replace(/'/g, "''")}'
---

${body.replace(/copilot-instructions\.md/g, 'AGENTS.md').trim()}
`;
  await writeFileEnsuringDir(
    path.join(ROOT, '.github', 'prompts', 'delegate-task.prompt.md'),
    BANNER + out,
  );
  console.log('Synced .github/prompts/delegate-task.prompt.md');
}

async function syncToolEntrypoints() {
  const claude = `# Claude Code

> **Do not add rules here.** Edit [\`AGENTS.md\`](AGENTS.md) and [\`agents/path-rules/\`](agents/path-rules/).

## Main instructions (always on)

@AGENTS.md

## Path rules (read when editing matching paths)

${(await fs.readdir(PATH_RULES_DIR))
  .filter((f) => f.endsWith('.md'))
  .map((f) => {
    const id = f.replace(/\.md$/, '');
    return `- [agents/path-rules/${f}](agents/path-rules/${f})`;
  })
  .join('\n')}

## Skills

Source: [\`.agents/skills/\`](.agents/skills/) — use \`/skill-name\` after \`pnpm run agent:install\`, or ask Claude to follow a skill file.

See [docs/agent-config.md](docs/agent-config.md).
`;
  await writeFileEnsuringDir(path.join(ROOT, 'CLAUDE.md'), claude);

  const gemini = `# Gemini CLI

@AGENTS.md

Path rules: \`agents/path-rules/\`. Skills: \`.agents/skills/\`.

Run \`pnpm run sync:agents\` after edits. See [docs/agent-config.md](docs/agent-config.md).
`;
  await writeFileEnsuringDir(path.join(ROOT, 'GEMINI.md'), gemini);

  console.log('Synced CLAUDE.md, GEMINI.md');
}

async function main() {
  await syncAgentsMd();
  await syncPathRules();
  await syncCopilotPrompts();
  await syncSkillMirrors();
  await syncToolEntrypoints();
  console.log('\nDone. Source: AGENTS.md, agents/path-rules/, .agents/skills/');
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
